INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_106' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , '위험등급 공란' , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
