mapper.delete:
DELETE SSQ.L_CDD_MNTN_DTLD
 WHERE MNTN_STNR_CODE = 'CDD_107'
   AND MNTN_DATE      = #{yyyymmdd}

mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_107' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , CASE WHEN A.CLNT_RISK_RTNG_CODE = 'H' THEN '위험등급 : H, 재수행예정일자(계산) : ' || TO_CHAR(ADD_MONTHS(TO_DATE(A.CDD_FLFL_DATE, 'YYYYMMDD'), 12), 'YYYYMMDD') || ', (DB) : ' || A.CDD_RE_FLFL_XPCN_DATE WHEN A.CLNT_RISK_RTNG_CODE = 'M' THEN '위험등급 : M, 재수행예정일자(계산) : ' || TO_CHAR(ADD_MONTHS(TO_DATE(A.CDD_FLFL_DATE, 'YYYYMMDD'), 24), 'YYYYMMDD') || ', (DB) : ' || A.CDD_RE_FLFL_XPCN_DATE WHEN A.CLNT_RISK_RTNG_CODE = 'L' THEN '위험등급 : L, 재수행예정일자(계산) : ' || TO_CHAR(ADD_MONTHS(TO_DATE(A.CDD_FLFL_DATE, 'YYYYMMDD'), 36), 'YYYYMMDD') || ', (DB) : ' || A.CDD_RE_FLFL_XPCN_DATE ELSE ' ' END , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_CMPL_YN = 'Y' AND ((A.CLNT_RISK_RTNG_CODE = 'H' AND (TO_CHAR(ADD_MONTHS(TO_DATE(A.CDD_FLFL_DATE, 'YYYYMMDD'), 12), 'YYYYMMDD') <> A.CDD_RE_FLFL_XPCN_DATE)) OR (A.CLNT_RISK_RTNG_CODE = 'M' AND (TO_CHAR(ADD_MONTHS(TO_DATE(A.CDD_FLFL_DATE, 'YYYYMMDD'), 24), 'YYYYMMDD') <> A.CDD_RE_FLFL_XPCN_DATE)) OR (A.CLNT_RISK_RTNG_CODE = 'L' AND (TO_CHAR(ADD_MONTHS(TO_DATE(A.CDD_FLFL_DATE, 'YYYYMMDD'), 36), 'YYYYMMDD') <> A.CDD_RE_FLFL_XPCN_DATE)))

mapper.delete:
DELETE SSQ.L_CDD_MNTN_DTLD
 WHERE MNTN_STNR_CODE = 'CDD_108'
   AND MNTN_DATE      = #{yyyymmdd}

mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_108' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , '재수행예정일자 : ' || TRIM(A.CDD_RE_FLFL_XPCN_DATE ) || ', 의무수행여부 : ' || A.CDD_DUTY_FLFL_TAGT_SECT_CODE , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_CMPL_YN = 'Y' AND A.CDD_RE_FLFL_XPCN_DATE <= (SELECT PREV_BSNS_DATE FROM SID.IDO_A_UUE_INSN_CALENDAR WHERE ENTY_ID = 1 AND TAGT_DATE = TO_CHAR(SYSDATE, 'YYYYMMDD')) AND A.CDD_DUTY_FLFL_TAGT_SECT_CODE <> 'Y'

mapper.delete:
DELETE SSQ.L_CDD_MNTN_DTLD
 WHERE MNTN_STNR_CODE = 'CDD_109'
   AND MNTN_DATE      = #{yyyymmdd}

mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_109' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , '당사자구분 : 대리인, 관계 : 상임대리인, 고객구분 : ' || CASE WHEN A.CDD_CLNT_SECT_CODE = '1' THEN '개인' WHEN A.CDD_CLNT_SECT_CODE = '3' THEN '비영리법인' ELSE ' ' END , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_CMPL_YN = 'Y' AND A.CDD_TAGT_SECT_CODE = '02' -- 대리인 AND A.CDD_AGNT_RLTP_SECT_CODE = '08' -- 상임대리인 AND A.CDD_CLNT_SECT_CODE <> '2' -- 영리법인

mapper.delete:
DELETE SSQ.L_CDD_MNTN_DTLD
 WHERE MNTN_STNR_CODE = 'CDD_110'
   AND MNTN_DATE      = #{yyyymmdd}

mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_110' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , CASE WHEN TRIM(A.ORIG_CLNT_NAME) IS NULL THEN '고객명 공란' || CASE WHEN TRIM(A.CDD_ORIG_CLNT_NO_CRYP) IS NULL THEN ', 실명번호 공란' ELSE '' END ELSE CASE WHEN TRIM(A.CDD_ORIG_CLNT_NO_CRYP) IS NULL THEN '실명번호 공란' ELSE '' END END , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_TAGT_SECT_CODE = '02' -- 대리인 AND (TRIM(A.ORIG_CLNT_NAME ) IS NULL OR TRIM(A.CDD_ORIG_CLNT_NO_CRYP ) IS NULL)

mapper.delete:
DELETE SSQ.L_CDD_MNTN_DTLD
 WHERE MNTN_STNR_CODE = 'CDD_111'
   AND MNTN_DATE      = #{yyyymmdd}

mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_111' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , '본인과 대리인의 실명번호 동일' , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_TAGT_SECT_CODE = '02' -- 대리인 AND TRIM(A.CDD_TAGT_CLNT_NO_CRYP ) = TRIM(A.CDD_ORIG_CLNT_NO_CRYP)

mapper.delete:
DELETE SSQ.L_CDD_MNTN_DTLD
 WHERE MNTN_STNR_CODE = 'CDD_112'
   AND MNTN_DATE      = #{yyyymmdd}

mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_112' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , '공란 : ' || CASE WHEN TRIM(A.BRDT) IS NULL THEN '생년월일' || CASE WHEN TRIM(A.GNDR_SECT_CODE) IS NULL THEN ', 성별' ELSE '' END ELSE CASE WHEN TRIM(A.GNDR_SECT_CODE) IS NULL THEN '성별' ELSE '' END END , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_CMPL_YN = 'Y' AND A.CDD_CLNT_SECT_CODE = '1' -- 개인 AND (TRIM(A.BRDT) IS NULL OR TRIM(A.GNDR_SECT_CODE) IS NULL)

mapper.delete:
DELETE SSQ.L_CDD_MNTN_DTLD
 WHERE MNTN_STNR_CODE = 'CDD_113'
   AND MNTN_DATE      = #{yyyymmdd}

mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_113' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , CASE WHEN X.DATE_ANLY_SDVL IS NULL THEN '생년월일 : 미존재 날짜(' || TRIM(A.BRDT) || ')' || CASE WHEN A.BRDT >= A.CDD_FLFL_DATE THEN ', 수행일자(' || A.CDD_FLFL_DATE || ') <= 생년월일(' || TRIM(A.BRDT) || ')' ELSE '' END ELSE CASE WHEN A.BRDT >= A.CDD_FLFL_DATE THEN '수행일자(' || A.CDD_FLFL_DATE || ') ≤ 생년월일(' || TRIM(A.BRDT) || ')' ELSE '' END END , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A LEFT OUTER JOIN SSQ.L_DATE_STND_VALU X ON X.DATE_TYPE_SDVL = 'YYYYMMDD' AND X.DATE_ANLY_SDVL = A.BRDT WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_CMPL_YN = 'Y' AND A.CDD_CLNT_SECT_CODE = '1' -- 개인 AND TRIM(A.BRDT) IS NOT NULL AND (A.BRDT >= A.CDD_FLFL_DATE OR X.DATE_ANLY_SDVL IS NULL)

mapper.delete:
DELETE SSQ.L_CDD_MNTN_DTLD
 WHERE MNTN_STNR_CODE = 'CDD_114'
   AND MNTN_DATE      = #{yyyymmdd}

mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_114' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , '공란 : ' || CASE WHEN A.NTNY_ID = 0 THEN '소속국가' || CASE WHEN A.RSDT_CNTY_ID = 0 THEN ', 거주국가' ELSE '' END ELSE CASE WHEN A.RSDT_CNTY_ID = 0 THEN '거주국가' ELSE '' END END , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_CMPL_YN = 'Y' --AND A.CDD_CLNT_SECT_CODE = '1' -- 개인 AND (A.NTNY_ID = 0 OR A.RSDT_CNTY_ID = 0)

