mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_201' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , 'CDD등록사유 : ' || A.CDD_RGSN_RESN_CODE || '.' || NVL((SELECT TRIM(T.CMN_CDVL_NAME) FROM SID.IDO_A_UWB_COM_CD_DTL T WHERE T.CMN_CODE_ID = '06757' AND T.CMN_CDVL = A.CDD_RGSN_RESN_CODE AND DEL_YN = 'N'), '') || CASE WHEN A.CDD_RGSN_RESN_CODE = '99' THEN '-' || TRIM(A.CDD_RGSN_RESN_NAME) ELSE '' END , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_RGSN_RESN_CODE NOT IN ('02', '04') AND A.RGBR_CODE IN (SELECT CNTNT FROM SSQ.NIC92B WHERE CD = 'IB_DTBR' )

mapper.delete:
