mapper.insert:
INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_204' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , '생년월일 : ' || TRIM(A.BRDT) || '인 미성년자가 고객ID : ' || A.CDD_ORIG_ENTY_ID || '(' || A.ORIG_CLNT_NAME || ')의 대리인으로 등록' , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A INNER JOIN SSQ.L_DATE_STND_VALU X1 ON X1.DATE_TYPE_SDVL = 'YYYYMMDD' AND X1.DATE_ANLY_SDVL = A.CDD_FLFL_DATE INNER JOIN SSQ.L_DATE_STND_VALU X2 ON X2.DATE_TYPE_SDVL = 'YYYYMMDD' AND X2.DATE_ANLY_SDVL = A.BRDT WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_CLNT_SECT_CODE = '1' -- 개인 AND TRIM(A.BRDT) IS NOT NULL AND TRIM(A.BRDT) <= #{yyyymmdd}
AND A.CDD_TAGT_SECT_CODE = '02' -- 대리인 AND TRUNC(MONTHS_BETWEEN(TO_DATE(X1.DATE_ANLY_SDVL, 'YYYYMMDD'), TO_DATE(X2.DATE_ANLY_SDVL, 'YYYYMMDD')) / 12) < 19

mapper.delete:
