INSERT INTO SSQ.L_CDD_MNTN_DTLD ( MNTN_DATE , MNTN_STNR_CODE , CDD_TAGT_ENTY_ID , CDD_FLFL_SQNO , MNTN_DTLS_CTNT , PRCE_DATE_TIME , ACTN_RSLT_SECT_CODE ) SELECT A.CDD_FLFL_DATE , 'CDD_210' , A.CDD_TAGT_ENTY_ID , A.CDD_FLFL_SQNO , '업종 : ' || A.STND_INDY_CLSN_CODE || '.' || NVL((SELECT TRIM(CMN_CDVL_NAME) FROM SID.IDO_A_UWB_COM_CD_DTL WHERE CMN_CODE_ID = '00631' AND DEL_YN='N' AND CMN_CDVL = A.STND_INDY_CLSN_CODE), '') , SYSDATE , 'N'
FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A WHERE 1 = 1 AND A.DEL_YN <> 'Y' AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL AND A.CLNT_RISK_RTNG_CODE IN ('H', 'M', 'L') AND A.PRCE_CHNL_SECT_CODE LIKE 'A%' AND A.CDD_FLFL_DATE = #{yyyymmdd}
AND A.CDD_CLNT_SECT_CODE = '2' -- 영리법인 AND A.TAGT_CLNT_NAME LIKE '%대부%' AND A.STND_INDY_CLSN_CODE <> '99998'

